use std::collections::HashMap;

#[derive(Clone, Debug)]
struct Config {
    mode: String,
    threads: u32,
    color: bool,
    label: String,
    endpoint: String,
}

fn parse_bool(s: &str) -> Option<bool> {
    match s {
        "true" | "1" | "yes" | "on" => Some(true),
        "false" | "0" | "no" | "off" => Some(false),
        _ => None,
    }
}

fn parse_kv_block(input: &str) -> HashMap<String, String> {
    let mut map = HashMap::new();
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if let Some((k, v)) = line.split_once('=') {
            map.insert(k.trim().to_string(), v.trim().to_string());
        }
    }
    map
}

fn merge(defaults: Config, file: &HashMap<String, String>, env: &HashMap<String, String>, cli: &HashMap<String, String>) -> Config {
    let mut cfg = defaults.clone();

    if let Some(v) = file.get("mode") {
        if !v.is_empty() {
            cfg.mode = v.clone();
        }
    }
    if let Some(v) = env.get("APP_MODE") {
        if !v.is_empty() {
            cfg.mode = v.clone();
        }
    }
    if let Some(v) = cli.get("mode") {
        if !v.is_empty() {
            cfg.mode = v.clone();
        }
    }

    if let Some(v) = file.get("threads") {
        if let Ok(n) = v.parse::<u32>() {
            if n > 0 {
                cfg.threads = n;
            }
        }
    }
    if let Some(v) = env.get("APP_THREADS") {
        if let Ok(n) = v.parse::<u32>() {
            if n > 0 {
                cfg.threads = n;
            }
        }
    }
    if let Some(v) = cli.get("threads") {
        if let Ok(n) = v.parse::<u32>() {
            if n > 0 {
                cfg.threads = n;
            }
        }
    }

    if let Some(v) = file.get("color") {
        if let Some(b) = parse_bool(v) {
            if b {
                cfg.color = true;
            }
        }
    }
    if let Some(v) = env.get("APP_COLOR") {
        if let Some(b) = parse_bool(v) {
            if b {
                cfg.color = true;
            }
        }
    }
    if let Some(v) = cli.get("color") {
        if let Some(b) = parse_bool(v) {
            if b {
                cfg.color = true;
            }
        }
    }

    if let Some(v) = file.get("label") {
        if !v.is_empty() {
            cfg.label = v.clone();
        }
    }
    if let Some(v) = env.get("APP_LABEL") {
        if !v.is_empty() {
            cfg.label = v.clone();
        }
    }
    if let Some(v) = cli.get("label") {
        if !v.is_empty() {
            cfg.label = v.clone();
        }
    }

    if let Some(v) = cli.get("endpoint") {
        cfg.endpoint = v.clone();
    } else if let Some(v) = env.get("APP_ENDPOINT") {
        cfg.endpoint = v.clone();
    } else if let Some(v) = file.get("endpoint") {
        cfg.endpoint = v.clone();
    }

    cfg
}

fn render(cfg: &Config) -> String {
    let label = if cfg.label.is_empty() { "<empty>" } else { &cfg.label };
    format!(
        "mode={}\nthreads={}\ncolor={}\nlabel={}\nendpoint={}",
        cfg.mode, cfg.threads, cfg.color, label, cfg.endpoint
    )
}

fn main() {
    let defaults = Config {
        mode: "safe".to_string(),
        threads: 4,
        color: true,
        label: "core".to_string(),
        endpoint: "https://default.example/api".to_string(),
    };

    let file = parse_kv_block(
        "mode=balanced
threads=8
color=true
label=file-tag
endpoint=https://file.example/api",
    );
    let env = parse_kv_block(
        "APP_MODE=
APP_THREADS=0
APP_COLOR=false
APP_LABEL=
APP_ENDPOINT=https://env.example/api",
    );
    let cli = parse_kv_block(
        "mode=off
color=false
label=
endpoint=https://cli.example/api",
    );

    let merged = merge(defaults, &file, &env, &cli);
    println!("{}", render(&merged));
}

