use std::collections::HashMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: String,
    pub score: i32,
    pub attempts: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ranked {
    pub rank: usize,
    pub name: String,
    pub score: i32,
    pub attempts: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<Ranked> {
    let mut merged: HashMap<String, (i32, u32)> = HashMap::new();
    for e in entries {
        let key = e.name.clone();
        let slot = merged.entry(key).or_insert((0, 0));
        slot.0 += e.score;
        slot.1 += e.attempts;
    }

    let mut rows: Vec<(String, i32, u32)> = merged
        .into_iter()
        .map(|(name, (score, attempts))| (name, score, attempts))
        .collect();

    rows.sort_by(|a, b| {
        b.1.cmp(&a.1)
            .then_with(|| a.0.cmp(&b.0))
    });

    let mut out = Vec::new();
    for (idx, (name, score, attempts)) in rows.into_iter().enumerate() {
        out.push(Ranked {
            rank: idx + 1,
            name,
            score,
            attempts,
        });
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    fn e(name: &str, score: i32, attempts: u32) -> Entry {
        Entry {
            name: name.to_string(),
            score,
            attempts,
        }
    }

    #[test]
    fn merges_case_insensitive_duplicates_and_uses_best_display_name() {
        let rows = leaderboard(&[
            e("alice", 12, 3),
            e("ALICE", 5, 1),
            e("Bob", 20, 2),
        ]);

        assert_eq!(
            rows,
            vec![
                Ranked { rank: 1, name: "Bob".into(), score: 20, attempts: 2 },
                Ranked { rank: 2, name: "ALICE".into(), score: 17, attempts: 4 },
            ]
        );
    }

    #[test]
    fn uses_dense_ranks_for_equal_scores() {
        let rows = leaderboard(&[
            e("A", 10, 3),
            e("B", 10, 1),
            e("C", 9, 1),
            e("D", 9, 2),
            e("E", 7, 1),
        ]);

        let got: Vec<(usize, &str, i32, u32)> = rows
            .iter()
            .map(|r| (r.rank, r.name.as_str(), r.score, r.attempts))
            .collect();

        assert_eq!(
            got,
            vec![
                (1, "B", 10, 1),
                (1, "A", 10, 3),
                (2, "C", 9, 1),
                (2, "D", 9, 2),
                (3, "E", 7, 1),
            ]
        );
    }

    #[test]
    fn tie_breaks_by_fewer_attempts_then_case_insensitive_name_then_original_name() {
        let rows = leaderboard(&[
            e("beta", 30, 4),
            e("Alpha", 30, 2),
            e("alpha", 30, 2),
            e("Bravo", 30, 2),
            e("charlie", 30, 2),
        ]);

        let got: Vec<(usize, String, i32, u32)> = rows
            .into_iter()
            .map(|r| (r.rank, r.name, r.score, r.attempts))
            .collect();

        assert_eq!(
            got,
            vec![
                (1, "Alpha".into(), 30, 2),
                (1, "Bravo".into(), 30, 2),
                (1, "charlie".into(), 30, 2),
                (1, "alpha".into(), 30, 2),
                (1, "beta".into(), 30, 4),
            ]
        );
    }

    #[test]
    fn duplicate_merge_can_change_tie_group_and_order() {
        let rows = leaderboard(&[
            e("Nora", 8, 2),
            e("nora", 8, 1),
            e("Omar", 16, 5),
            e("Pia", 16, 2),
            e("Quin", 14, 1),
        ]);

        assert_eq!(
            rows,
            vec![
                Ranked { rank: 1, name: "Nora".into(), score: 16, attempts: 3 },
                Ranked { rank: 1, name: "Pia".into(), score: 16, attempts: 2 },
                Ranked { rank: 1, name: "Omar".into(), score: 16, attempts: 5 },
                Ranked { rank: 2, name: "Quin".into(), score: 14, attempts: 1 },
            ]
        );
    }
}

