const INPUT: &str = "amy|7|ops|active\nzoe|10|dev|inactive\nmax|3|sales\nBo|5|ops|active\nivy|0|dev|active\nleo|4|Dev|active\nmia|8|hr|pending\nnoa|11|ops|active\neli|6|ops|active|extra";

fn validate(line: &str) -> Result<(String, u32, String), &'static str> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 3 {
        return Err("field_count");
    }

    let name = parts[0];
    if name.len() < 2 || !name.chars().all(|c| c.is_ascii_alphabetic()) {
        return Err("name");
    }

    let score: u32 = parts[1].parse().map_err(|_| "score")?;
    if score > 10 {
        return Err("score");
    }

    let dept = parts[2];
    if dept != "ops" && dept != "dev" && dept != "hr" && dept != "sales" {
        return Err("dept");
    }

    Ok((name.to_string(), score, dept.to_string()))
}

fn main() {
    let mut out = Vec::new();
    for (idx, line) in INPUT.lines().enumerate() {
        match validate(line) {
            Ok((name, score, dept)) => out.push(format!("OK:{}:{}:{}", name, score, dept)),
            Err(code) => out.push(format!("ERR {}: {}", idx + 1, code)),
        }
    }
    print!("{}", out.join("\n"));
}

