use std::collections::HashMap;

#[derive(Clone, Debug)]
struct Config {
    host: Option<String>,
    port: Option<u16>,
    color: Option<bool>,
    mode: Option<String>,
}

impl Config {
    fn empty() -> Self {
        Self {
            host: None,
            port: None,
            color: None,
            mode: None,
        }
    }
}

fn parse_file(input: &str) -> Config {
    let mut cfg = Config::empty();
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        let Some((k, v)) = line.split_once('=') else { continue };
        let key = k.trim();
        let val = v.trim();
        match key {
            "host" => {
                if !val.is_empty() {
                    cfg.host = Some(val.to_string());
                }
            }
            "port" => {
                if let Ok(p) = val.parse::<u16>() {
                    cfg.port = Some(p);
                }
            }
            "color" => match val {
                "true" => cfg.color = Some(true),
                "false" => cfg.color = Some(false),
                _ => {}
            },
            "mode" => {
                if !val.is_empty() {
                    cfg.mode = Some(val.to_string());
                }
            }
            _ => {}
        }
    }
    cfg
}

fn parse_env(env: &HashMap<&str, &str>) -> Config {
    let mut cfg = Config::empty();
    if let Some(v) = env.get("APP_HOST") {
        if !v.is_empty() {
            cfg.host = Some((*v).to_string());
        }
    }
    if let Some(v) = env.get("APP_PORT") {
        if let Ok(p) = v.parse::<u16>() {
            cfg.port = Some(p);
        }
    }
    if let Some(v) = env.get("APP_COLOR") {
        cfg.color = Some(*v == "true");
    }
    if let Some(v) = env.get("APP_MODE") {
        if !v.is_empty() {
            cfg.mode = Some((*v).to_string());
        }
    }
    cfg
}

fn parse_cli(args: &[&str]) -> Config {
    let mut cfg = Config::empty();
    let mut i = 0;
    while i < args.len() {
        match args[i] {
            "--host" if i + 1 < args.len() => {
                let v = args[i + 1];
                if !v.is_empty() {
                    cfg.host = Some(v.to_string());
                }
                i += 2;
            }
            "--port" if i + 1 < args.len() => {
                if let Ok(p) = args[i + 1].parse::<u16>() {
                    cfg.port = Some(p);
                }
                i += 2;
            }
            "--color" => {
                cfg.color = Some(true);
                i += 1;
            }
            "--no-color" => {
                i += 1;
            }
            "--mode" if i + 1 < args.len() => {
                let v = args[i + 1];
                if !v.is_empty() {
                    cfg.mode = Some(v.to_string());
                }
                i += 2;
            }
            _ => i += 1,
        }
    }
    cfg
}

fn merge(defaults: Config, file: Config, env: Config, cli: Config) -> (Config, HashMap<&'static str, &'static str>) {
    let mut sources = HashMap::new();

    let host = defaults.host
        .or(file.host)
        .or(env.host)
        .or(cli.host);
    let port = defaults.port
        .or(file.port)
        .or(env.port)
        .or(cli.port);
    let color = defaults.color
        .or(file.color)
        .or(env.color)
        .or(cli.color);
    let mode = defaults.mode
        .or(file.mode)
        .or(env.mode)
        .or(cli.mode);

    sources.insert("host", if cli.host.is_some() { "cli" } else if env.host.is_some() { "env" } else if file.host.is_some() { "file" } else { "default" });
    sources.insert("port", if cli.port.is_some() { "cli" } else if env.port.is_some() { "env" } else if file.port.is_some() { "file" } else { "default" });
    sources.insert("color", if cli.color.is_some() { "cli" } else if env.color.is_some() { "env" } else if file.color.is_some() { "file" } else { "default" });
    sources.insert("mode", if cli.mode.is_some() { "cli" } else if env.mode.is_some() { "env" } else if file.mode.is_some() { "file" } else { "default" });

    (
        Config {
            host,
            port,
            color,
            mode,
        },
        sources,
    )
}

fn main() {
    let defaults = Config {
        host: Some("localhost".to_string()),
        port: Some(3000),
        color: Some(true),
        mode: Some("release".to_string()),
    };

    let file_cfg = parse_file("host=file.example\nport=7000\ncolor=true\nmode=prod\n");

    let env_cfg = parse_env(&HashMap::from([
        ("APP_HOST", "env.example"),
        ("APP_PORT", "8081"),
        ("APP_COLOR", "maybe"),
        ("APP_MODE", "debug"),
    ]));

    let cli_cfg = parse_cli(&[
        "--host",
        "",
        "--no-color",
    ]);

    let (resolved, source) = merge(defaults, file_cfg, env_cfg, cli_cfg);

    println!("host={}", resolved.host.unwrap_or_default());
    println!("port={}", resolved.port.unwrap_or(0));
    println!("color={}", resolved.color.unwrap_or(false));
    println!("mode={}", resolved.mode.unwrap_or_default());
    println!("source_host={}", source["host"]);
    println!("source_port={}", source["port"]);
    println!("source_color={}", source["color"]);
    println!("source_mode={}", source["mode"]);
}

