#[derive(Clone, Copy)]
struct Ticket {
    dept: &'static str,
    region: &'static str,
    status: &'static str,
    count: u32,
    archived: bool,
}

fn build_report(rows: &[Ticket]) -> String {
    use std::collections::BTreeMap;

    let mut groups: BTreeMap<&str, BTreeMap<&str, (u32, u32)>> = BTreeMap::new();

    for row in rows {
        let dept = groups.entry(row.dept).or_default();
        let entry = dept.entry(row.region).or_insert((0, 0));
        if row.status == "open" {
            entry.0 += row.count;
        } else {
            entry.1 += row.count;
        }
    }

    let mut out = String::new();
    for (dept, regions) in groups {
        out.push_str(&format!("REPORT {dept}\n"));
        let mut dept_open = 0;
        let mut dept_closed = 0;
        for (region, (open, closed)) in regions {
            dept_open += open;
            dept_closed += closed;
            out.push_str(&format!("{region}: open={open}, closed={closed}, total={}\n", open + closed));
        }
        out.push_str(&format!("TOTAL {dept}: open={dept_open}, closed={dept_closed}, total={}\n\n", dept_open + dept_closed));
    }
    out
}

