fn build_report(rows: &[Ticket]) -> String {
    use std::collections::BTreeMap;

    let mut groups: BTreeMap<&str, BTreeMap<&str, (u32, u32)>> = BTreeMap::new();

    for row in rows {
        if row.archived {
            continue;
        }
        let dept = groups.entry(row.dept).or_default();
        let entry = dept.entry(row.region).or_insert((0, 0));
        match row.status {
            "open" => entry.0 += row.count,
            "closed" => entry.1 += row.count,
            _ => {}
        }
    }

    let mut out = String::new();
    let mut first_dept = true;
    for (dept, regions) in groups {
        let mut lines: Vec<String> = Vec::new();
        let mut dept_open = 0;
        let mut dept_closed = 0;

        for (region, (open, closed)) in regions {
            let total = open + closed;
            if total == 0 {
                continue;
            }
            dept_open += open;
            dept_closed += closed;
            lines.push(format!("{region} | closed={closed} | open={open} | total={total}"));
        }

        let dept_total = dept_open + dept_closed;
        if dept_total == 0 {
            continue;
        }

        if !first_dept {
            out.push_str("\n\n");
        }
        first_dept = false;
        out.push_str(&format!("ACTIVE {} REPORT\n", dept.to_ascii_uppercase()));
        for (idx, line) in lines.iter().enumerate() {
            if idx > 0 {
                out.push('\n');
            }
            out.push_str(line);
        }
        out.push('\n');
        out.push_str(&format!("TOTAL {} | closed={} | open={} | total={}", dept.to_ascii_uppercase(), dept_closed, dept_open, dept_total));
    }
    out
}

