#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Job {
    pub id: u32,
    pub owner: &'static str,
    pub team: &'static str,
    pub active: bool,
    pub priority: u8,
    pub retries: u8,
    pub tags: &'static [&'static str],
    pub cooldown: bool,
}

pub fn select_jobs(jobs: &[Job], team: &str, limit: usize) -> Vec<String> {
    let mut picked: Vec<&Job> = jobs
        .iter()
        .filter(|j| j.team == team)
        .filter(|j| j.active)
        .filter(|j| j.priority >= 3)
        .filter(|j| !j.cooldown)
        .collect();

    picked.sort_by(|a, b| b.priority.cmp(&a.priority).then_with(|| a.id.cmp(&b.id)));

    picked
        .into_iter()
        .take(limit)
        .map(|j| format!("{}#{}:{}", j.team, j.id, j.owner))
        .collect()
}

