fn validate_line(line: &str) -> Result<(String, String, i32), String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() < 3 {
        return Err(format!("bad_field_count:{}", parts.len()));
    }

    let id = parts[0];
    let name = parts[1];
    let score: i32 = match parts[2].parse() {
        Ok(v) => v,
        Err(_) => return Err(format!("bad_score_range:{}", parts[2])),
    };

    if id.len() < 2 || !id.chars().all(|c| c.is_ascii_alphanumeric()) {
        return Err(format!("bad_id_format:{}", id));
    }

    if !name.chars().all(|c| c.is_ascii_alphabetic() || c == '-' || c == '_') {
        return Err(format!("bad_name_format:{}", name));
    }

    if score > 100 {
        return Err(format!("bad_score_range:{}", parts[2]));
    }

    Ok((id.to_string(), name.to_string(), score))
}

fn main() {
    let input = "m9|zoe|100\nr2|bob|45\nAA|mia|77\na1|alice|88\nabc|ned|73\nb4|ALICE|52\nc5|eve_|61\nd6|tom-|70\nh7|ivy-rose|0\nk1|max|-1\nq3|una|101\nz9|amy\np8|leo|33|extra\n";

    let mut ok = Vec::new();
    let mut errs = Vec::new();

    for line in input.lines() {
        if line.is_empty() {
            continue;
        }
        match validate_line(line) {
            Ok((id, name, score)) => ok.push(format!("{}:{}:{}", id, name, score)),
            Err(e) => errs.push(e),
        }
    }

    ok.sort();
    errs.sort();

    println!("ok:{}", ok.len());
    for row in ok {
        println!("{}", row);
    }
    for err in errs {
        println!("{}", err);
    }
}

