fn validate_line(line: &str) -> Result<(String, String, i32), String> {
    let parts: Vec<&str> = line.split('|').collect();
    if parts.len() != 3 {
        return Err(format!("bad_field_count:{}", parts.len()));
    }

    let id = parts[0];
    let name = parts[1];
    let score_raw = parts[2];
    let score: i32 = match score_raw.parse() {
        Ok(v) => v,
        Err(_) => return Err(format!("bad_score_range:{}", score_raw)),
    };

    let id_bytes = id.as_bytes();
    if id_bytes.len() != 2
        || !id_bytes[0].is_ascii_lowercase()
        || !id_bytes[1].is_ascii_digit()
    {
        return Err(format!("bad_id_format:{}", id));
    }

    let name_bytes = name.as_bytes();
    if name_bytes.is_empty()
        || !name_bytes[0].is_ascii_lowercase()
        || !name_bytes[name_bytes.len() - 1].is_ascii_lowercase()
        || !name_bytes
            .iter()
            .all(|b| b.is_ascii_lowercase() || *b == b'-')
    {
        return Err(format!("bad_name_format:{}", name));
    }

    if !(0..=100).contains(&score) {
        return Err(format!("bad_score_range:{}", score_raw));
    }

    Ok((id.to_string(), name.to_string(), score))
}

