pub fn parse_records(input: &str) -> Vec<(String, i32, String)> {
    let mut out = Vec::new();
    for line in input.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let mut id = "";
        let mut qty = 0;
        let mut tag = "";

        for part in line.split('|') {
            let mut kv = part.splitn(2, '=');
            let key = kv.next().unwrap_or("").trim();
            let value = kv.next().unwrap_or("").trim();
            match key {
                "id" => id = value,
                "qty" => qty = value.parse::<i32>().unwrap_or(0),
                "tag" => tag = value,
                _ => {}
            }
        }

        if !id.is_empty() {
            out.push((id.to_string(), qty, tag.to_string()));
        }
    }
    out
}

