#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
    Service,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    AdminPanel,
    Billing,
    Audit,
    Support,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Approve,
}

pub fn policy_decision(role: Role, route: Route, action: Action, suspended: bool) -> &'static str {
    if suspended {
        return "deny";
    }

    match route {
        Route::Home => "allow",
        Route::Profile => match action {
            Action::View => "allow",
            _ => "deny",
        },
        Route::AdminPanel => match role {
            Role::Admin => "allow",
            _ => "deny",
        },
        Route::Billing => match role {
            Role::Admin => "allow",
            Role::Member => "allow",
            _ => "deny",
        },
        Route::Audit => match role {
            Role::Admin => "allow",
            _ => "deny",
        },
        Route::Support => match role {
            Role::Moderator => "allow",
            Role::Admin => "allow",
            _ => "deny",
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn guests_have_limited_access() {
        assert_eq!(policy_decision(Role::Guest, Route::Home, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Guest, Route::Profile, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Guest, Route::Profile, Action::Edit, false), "deny");
        assert_eq!(policy_decision(Role::Guest, Route::Billing, Action::View, false), "deny");
    }

    #[test]
    fn members_can_manage_own_profile_and_view_billing() {
        assert_eq!(policy_decision(Role::Member, Route::Profile, Action::Edit, false), "allow");
        assert_eq!(policy_decision(Role::Member, Route::Profile, Action::Delete, false), "deny");
        assert_eq!(policy_decision(Role::Member, Route::Billing, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Member, Route::Billing, Action::Edit, false), "deny");
    }

    #[test]
    fn moderators_handle_support_and_audit_views_only() {
        assert_eq!(policy_decision(Role::Moderator, Route::Support, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Moderator, Route::Support, Action::Approve, false), "allow");
        assert_eq!(policy_decision(Role::Moderator, Route::Audit, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Moderator, Route::Audit, Action::Delete, false), "deny");
        assert_eq!(policy_decision(Role::Moderator, Route::AdminPanel, Action::View, false), "deny");
    }

    #[test]
    fn admins_have_broad_access_but_not_delete_everywhere() {
        assert_eq!(policy_decision(Role::Admin, Route::AdminPanel, Action::Approve, false), "allow");
        assert_eq!(policy_decision(Role::Admin, Route::Billing, Action::Edit, false), "allow");
        assert_eq!(policy_decision(Role::Admin, Route::Audit, Action::Delete, false), "deny");
        assert_eq!(policy_decision(Role::Admin, Route::Support, Action::Delete, false), "allow");
    }

    #[test]
    fn service_has_specialized_machine_access() {
        assert_eq!(policy_decision(Role::Service, Route::Audit, Action::View, false), "allow");
        assert_eq!(policy_decision(Role::Service, Route::Support, Action::Approve, false), "deny");
        assert_eq!(policy_decision(Role::Service, Route::Billing, Action::View, false), "deny");
    }

    #[test]
    fn suspension_only_blocks_human_roles() {
        assert_eq!(policy_decision(Role::Guest, Route::Home, Action::View, true), "deny");
        assert_eq!(policy_decision(Role::Member, Route::Profile, Action::Edit, true), "deny");
        assert_eq!(policy_decision(Role::Service, Route::Audit, Action::View, true), "allow");
    }
}

