use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Row {
    dept: &'static str,
    region: &'static str,
    units: i32,
    revenue: i32,
    active: bool,
}

#[derive(Default, Clone, Copy)]
struct Totals {
    txns: i32,
    units: i32,
    revenue: i32,
}

fn main() {
    let rows = vec![
        Row { dept: "Sales", region: "East", units: 5, revenue: 50, active: true },
        Row { dept: "Sales", region: "East", units: 2, revenue: 20, active: true },
        Row { dept: "Sales", region: "West", units: 0, revenue: 0, active: true },
        Row { dept: "Sales", region: "West", units: 1, revenue: 10, active: true },
        Row { dept: "Support", region: "North", units: 0, revenue: 0, active: true },
        Row { dept: "Support", region: "South", units: 3, revenue: 0, active: true },
        Row { dept: "Support", region: "East", units: 2, revenue: 20, active: false },
        Row { dept: "Engineering", region: "North", units: 7, revenue: 70, active: true },
        Row { dept: "Engineering", region: "South", units: 4, revenue: 40, active: true },
        Row { dept: "Engineering", region: "East", units: -1, revenue: -10, active: true },
    ];

    println!("{}", build_report(&rows));
}

fn build_report(rows: &[Row]) -> String {
    let mut grouped: BTreeMap<&str, BTreeMap<&str, Totals>> = BTreeMap::new();

    for row in rows {
        if !row.active {
            continue;
        }
        let dept = grouped.entry(row.dept).or_default();
        let totals = dept.entry(row.region).or_default();
        totals.txns += 1;
        totals.units += row.units;
        totals.revenue += row.revenue;
    }

    let mut out = String::from("Department report\n");
    let mut grand = Totals::default();

    for (dept_name, regions) in grouped {
        out.push_str(&format!("Department: {}\n", dept_name));
        let mut dept_total = Totals::default();
        for (region, totals) in regions {
            out.push_str(&format!(
                "  {} | txns={} | units={} | revenue={}\n",
                region, totals.txns, totals.units, totals.revenue
            ));
            dept_total.txns += totals.txns;
            dept_total.units += totals.units;
            dept_total.revenue += totals.revenue;
        }
        out.push_str(&format!(
            "  Total | txns={} | units={} | revenue={}\n",
            dept_total.txns, dept_total.units, dept_total.revenue
        ));
        grand.txns += dept_total.txns;
        grand.units += dept_total.units;
        grand.revenue += dept_total.revenue;
    }

    out.push_str(&format!(
        "Grand total | txns={} | units={} | revenue={}",
        grand.txns, grand.units, grand.revenue
    ));
    out
}

