            continue;
        };

        let mut lines: Vec<(&str, Totals)> = regions
            .iter()
            .filter_map(|(region, totals)| {
                if totals.units > 0 && totals.revenue > 0 {
                    Some((*region, *totals))
                } else {
                    None
                }
            })
            .collect();

        if lines.is_empty() {
            continue;
