enum Item {
    Alert { urgent: bool, silent: bool },
    Ticket { vip: bool },
    Ops,
    Bulk(u8),
    Ignore,
}

fn summarize(item: &Item, count: u32) -> String {
    match item {
        Item::Alert { urgent, .. } if *urgent => format!("watch => {} [alert]", count),
        Item::Alert { silent: true, .. } => format!("ignore => {} [quiet]", count),
        Item::Alert { .. } => format!("watch => {} [alert]", count),
        Item::Ticket { vip: true } => format!("queue => {} [vip]", count),
        Item::Ticket { vip: false } => format!("queue => {} [ticket]", count),
        Item::Ops => format!("watch => {} [ops]", count),
        Item::Bulk(n) if *n > 2 => format!("queue => {} [bulk]", count),
        Item::Bulk(_) => format!("ignore => {} [bulk]", count),
        Item::Ignore => format!("ignore => {} [none]", count),
    }
}

fn merge(a: &Item, b: &Item, count: u32) -> String {
    match (a, b) {
        (Item::Alert { urgent: true, .. }, Item::Ticket { .. }) => {
            format!("watch => {} [alert+ticket]", count)
        }
        (Item::Ticket { .. }, Item::Ops) | (Item::Ops, Item::Ticket { .. }) => {
            format!("queue => {} [ticket+ops]", count)
        }
        (Item::Alert { .. }, Item::Alert { .. }) => format!("watch => {} [alert-pair]", count),
        (Item::Bulk(n), Item::Ticket { .. }) | (Item::Ticket { .. }, Item::Bulk(n)) if *n >= 3 => {
            format!("queue => {} [ticket+bulk]", count)
        }
        (_, Item::Ignore) | (Item::Ignore, _) => format!("ignore => {} [none]", count),
        _ => summarize(a, count),
    }
}

fn main() {
    let lines = vec![
        merge(
            &Item::Alert {
                urgent: true,
                silent: false,
            },
            &Item::Ops,
            3,
        ),
        merge(&Item::Ticket { vip: true }, &Item::Alert { urgent: false, silent: false }, 2),
        summarize(&Item::Ops, 1),
        merge(&Item::Bulk(4), &Item::Ticket { vip: false }, 3),
        summarize(&Item::Ticket { vip: false }, 1),
        summarize(&Item::Alert { urgent: true, silent: true }, 2),
        summarize(&Item::Alert { urgent: false, silent: true }, 1),
        summarize(&Item::Ignore, 1),
    ];

    for line in lines {
        println!("{}", line);
    }
}

