#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Status {
    Ready,
    Snoozed,
    Disabled,
}

#[derive(Clone, Debug)]
pub struct Candidate {
    pub id: &'static str,
    pub status: Status,
    pub score: i32,
    pub seen_at: Option<u32>,
    pub hidden: bool,
}

pub fn pick_candidates(items: &[Candidate], now_minute: u32) -> Vec<&'static str> {
    let mut out: Vec<_> = items
        .iter()
        .filter(|c| c.status == Status::Ready)
        .filter(|c| !c.hidden)
        .filter(|c| c.score > 0)
        .filter_map(|c| {
            let age = now_minute.saturating_sub(c.seen_at.unwrap_or(now_minute));
            if age > 30 {
                Some((c.id, c.score, age))
            } else {
                None
            }
        })
        .collect();

    out.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| b.2.cmp(&a.2)).then_with(|| a.0.cmp(b.0)));
    out.into_iter().map(|(id, _, _)| id).collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    fn c(
        id: &'static str,
        status: Status,
        score: i32,
        seen_at: Option<u32>,
        hidden: bool,
    ) -> Candidate {
        Candidate {
            id,
            status,
            score,
            seen_at,
            hidden,
        }
    }

    #[test]
    fn excludes_hidden_disabled_snoozed_low_score_and_recent() {
        let items = vec![
            c("ready-ok", Status::Ready, 4, Some(20), false),
            c("hidden", Status::Ready, 10, Some(0), true),
            c("disabled", Status::Disabled, 10, Some(0), false),
            c("snoozed", Status::Snoozed, 10, Some(0), false),
            c("zero-score", Status::Ready, 0, Some(0), false),
            c("negative-score", Status::Ready, -3, Some(0), false),
            c("recent", Status::Ready, 9, Some(71), false),
        ];

        assert_eq!(pick_candidates(&items, 100), vec!["ready-ok"]);
    }

    #[test]
    fn keeps_never_seen_items_and_uses_them_after_seen_items_on_tie() {
        let items = vec![
            c("old-seen", Status::Ready, 5, Some(10), false),
            c("never-seen", Status::Ready, 5, None, false),
            c("higher-score", Status::Ready, 7, Some(95), false),
        ];

        assert_eq!(pick_candidates(&items, 100), vec!["higher-score", "old-seen", "never-seen"]);
    }

    #[test]
    fn threshold_is_inclusive_at_thirty_minutes() {
        let items = vec![
            c("exact-thirty", Status::Ready, 3, Some(70), false),
            c("twenty-nine", Status::Ready, 9, Some(71), false),
        ];

        assert_eq!(pick_candidates(&items, 100), vec!["exact-thirty"]);
    }

    #[test]
    fn deduplicates_ids_by_best_eligible_entry_before_sorting() {
        let items = vec![
            c("dup", Status::Ready, 2, Some(10), false),
            c("dup", Status::Ready, 8, Some(80), false),
            c("dup", Status::Ready, 6, None, false),
            c("peer", Status::Ready, 6, Some(1), false),
        ];

        assert_eq!(pick_candidates(&items, 100), vec!["peer", "dup"]);
    }

    #[test]
    fn duplicate_selection_ignores_ineligible_variants_and_uses_seen_recency_then_id() {
        let items = vec![
            c("beta", Status::Ready, 4, Some(10), false),
            c("alpha", Status::Ready, 4, Some(10), false),
            c("gamma", Status::Ready, 4, None, false),
            c("alpha", Status::Disabled, 100, Some(0), false),
            c("beta", Status::Ready, 7, Some(95), false),
            c("beta", Status::Ready, 8, Some(5), true),
        ];

        assert_eq!(pick_candidates(&items, 100), vec!["alpha", "beta", "gamma"]);
    }
}

