enum Tag {
    Priority,
    Gift,
    International,
    Bulk,
    Unknown,
}

enum Mode {
    Standard,
    Expedite,
    Freight,
}

fn parse_tag(s: &str) -> Tag {
    match s {
        "priority" => Tag::Priority,
        "gift" => Tag::Gift,
        "international" => Tag::International,
        "bulk" => Tag::Bulk,
        _ => Tag::Unknown,
    }
}

fn parse_mode(s: &str) -> Mode {
    match s {
        "expedite" => Mode::Expedite,
        "freight" => Mode::Freight,
        _ => Mode::Standard,
    }
}

fn label(tag: Tag, mode: Mode) -> &'static str {
    match mode {
        Mode::Expedite => "EXPEDITE",
        Mode::Freight => "FREIGHT",
        Mode::Standard => match tag {
            Tag::Priority => "PRIORITY",
            Tag::Gift => "GIFT",
            Tag::International => "INTL",
            Tag::Bulk => "BULK",
            Tag::Unknown => "REJECT",
        },
    }
}

