const INPUT: &str = "alice,engineering,34,88\nBob,engineering,34,88\ncarol,Engineering,34,88\ndave,sales,0,88\nerin,sales,25,101\nzane,ops,1,100\nmia,ops,20\nivy,ops,20,77,extra\nleo_2,ops,20,77\n";

fn parse_line(line: &str) -> Result<(String, String, u32, u32), &'static str> {
    let parts: Vec<&str> = line.split(',').collect();
    if parts.len() < 4 {
        return Err("bad field count");
    }

    let name = parts[0];
    if name.is_empty() || !name.chars().all(|c| c.is_alphabetic()) {
        return Err("bad name");
    }

    let dept = parts[1];
    if dept.is_empty() {
        return Err("bad dept");
    }

    let age: u32 = parts[2].parse().map_err(|_| "bad age")?;
    if age > 99 {
        return Err("bad age");
    }

    let score: u32 = parts[3].parse().map_err(|_| "bad score")?;
    if score > 100 {
        return Err("bad score");
    }

    Ok((name.to_string(), dept.to_string(), age, score))
}

fn main() {
    let mut valid = Vec::new();
    let mut invalid = Vec::new();

    for (idx, line) in INPUT.lines().enumerate() {
        match parse_line(line) {
            Ok((name, dept, age, score)) => valid.push(format!("{}|{}|{}|{}", name, dept, age, score)),
            Err(msg) => invalid.push(format!("{}:{}", idx + 1, msg)),
        }
    }

    println!("valid:{}", valid.len());
    for row in &valid {
        println!("{}", row);
    }
    println!("invalid:{}", invalid.len());
    for row in &invalid {
        println!("{}", row);
    }
}

