#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    AdminPanel,
    ModQueue,
    Billing,
    Support,
    Api,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Refund,
    BanUser,
}

pub fn is_allowed(role: Role, route: Route, action: Action) -> bool {
    match route {
        Route::Home => true,
        Route::Profile => matches!(action, Action::View | Action::Edit),
        Route::AdminPanel => matches!(role, Role::Admin),
        Route::ModQueue => matches!(role, Role::Moderator | Role::Admin),
        Route::Billing => matches!(role, Role::Member | Role::Admin) && matches!(action, Action::View),
        Route::Support => !matches!(action, Action::Delete),
        Route::Api => match role {
            Role::Admin => true,
            Role::Moderator => !matches!(action, Action::Refund),
            _ => matches!(action, Action::View),
        },
    }
}

#[cfg(test)]
mod tests {
    use super::{is_allowed, Action::*, Role::*, Route::*};

    #[test]
    fn guest_profile_is_view_only() {
        assert!(is_allowed(Guest, Profile, View));
        assert!(!is_allowed(Guest, Profile, Edit));
    }

    #[test]
    fn member_profile_can_edit_but_not_delete() {
        assert!(is_allowed(Member, Profile, Edit));
        assert!(!is_allowed(Member, Profile, Delete));
    }

    #[test]
    fn home_route_allows_only_views() {
        assert!(is_allowed(Guest, Home, View));
        assert!(!is_allowed(Admin, Home, Delete));
    }

    #[test]
    fn billing_refunds_require_admin() {
        assert!(is_allowed(Admin, Billing, Refund));
        assert!(!is_allowed(Member, Billing, Refund));
        assert!(is_allowed(Member, Billing, View));
    }

    #[test]
    fn support_delete_needs_staff_and_ban_is_admin_only() {
        assert!(!is_allowed(Member, Support, Delete));
        assert!(is_allowed(Moderator, Support, Delete));
        assert!(!is_allowed(Moderator, Support, BanUser));
        assert!(is_allowed(Admin, Support, BanUser));
    }

    #[test]
    fn mod_queue_requires_staff_and_only_view_or_ban() {
        assert!(!is_allowed(Member, ModQueue, View));
        assert!(is_allowed(Moderator, ModQueue, View));
        assert!(is_allowed(Admin, ModQueue, BanUser));
        assert!(!is_allowed(Moderator, ModQueue, Delete));
    }

    #[test]
    fn api_has_role_specific_rules() {
        assert!(is_allowed(Guest, Api, View));
        assert!(!is_allowed(Guest, Api, Edit));
        assert!(is_allowed(Moderator, Api, Delete));
        assert!(!is_allowed(Moderator, Api, Refund));
        assert!(is_allowed(Admin, Api, Refund));
    }

    #[test]
    fn admin_panel_is_admin_only_and_view_only() {
        assert!(!is_allowed(Moderator, AdminPanel, View));
        assert!(is_allowed(Admin, AdminPanel, View));
        assert!(!is_allowed(Admin, AdminPanel, Delete));
    }
}

