use std::collections::BTreeMap;

#[derive(Clone, Copy)]
struct Row {
    region: &'static str,
    dept: &'static str,
    gross: i32,
    returns: i32,
    active: bool,
}

#[derive(Default, Clone, Copy)]
struct Totals {
    tx: i32,
    gross: i32,
    returns: i32,
}

fn main() {
    let rows = vec![
        Row { region: "North", dept: "Sales", gross: 70, returns: 10, active: true },
        Row { region: "North", dept: "Sales", gross: 30, returns: 0, active: true },
        Row { region: "North", dept: "Ops", gross: 0, returns: 0, active: true },
        Row { region: "North", dept: "Support", gross: 0, returns: 0, active: false },
        Row { region: "South", dept: "Ops", gross: 20, returns: 25, active: true },
        Row { region: "South", dept: "Support", gross: 10, returns: 0, active: true },
        Row { region: "South", dept: "Sales", gross: 0, returns: 0, active: true },
        Row { region: "East", dept: "Sales", gross: 120, returns: 0, active: true },
        Row { region: "East", dept: "Ops", gross: 15, returns: 5, active: true },
        Row { region: "East", dept: "Ops", gross: 25, returns: 0, active: true },
        Row { region: "West", dept: "Sales", gross: 0, returns: 0, active: true },
    ];

    let mut by_region: BTreeMap<&str, BTreeMap<&str, Totals>> = BTreeMap::new();
    let mut grand = Totals::default();

    for row in rows {
        let dept = by_region.entry(row.region).or_default().entry(row.dept).or_default();
        dept.tx += 1;
        dept.gross += row.gross;
        dept.returns += row.returns;
        grand.tx += 1;
        grand.gross += row.gross;
        grand.returns += row.returns;
    }

    println!("SALES REPORT");
    for (region, depts) in by_region {
        println!("Region: {}", region);
        let mut region_total = Totals::default();
        for (dept, total) in depts {
            println!(
                "  Dept: {} | tx={} | gross={} | returns={} | net={}",
                dept,
                total.tx,
                total.gross,
                total.returns,
                total.gross - total.returns
            );
            region_total.tx += total.tx;
            region_total.gross += total.gross;
            region_total.returns += total.returns;
        }
        println!(
            "  Region Total | tx={} | gross={} | returns={} | net={}",
            region_total.tx,
            region_total.gross,
            region_total.returns,
            region_total.gross - region_total.returns
        );
    }
    println!(
        "GRAND TOTAL | tx={} | gross={} | returns={} | net={}",
        grand.tx,
        grand.gross,
        grand.returns,
        grand.gross - grand.returns
    );
}

