            Entry { name: "Ivy".into(), score: 120, solved: 5, penalty: 110 },
            Entry { name: "Ivy".into(), score: 120, solved: 5, penalty: 80 },
            Entry { name: "Moe".into(), score: 120, solved: 5, penalty: 70 },
        ]);

        assert_eq!(rows[1].name, "Ivy");
        assert_eq!(rows[1].score, 120);
        assert_eq!(rows[1].solved, 5);
        assert_eq!(rows[1].penalty, 80);
