            Entry { name: "AL".into(), score: 200, solved: 6, penalty: 40 },
            Entry { name: "bob".into(), score: 200, solved: 5, penalty: 10 },
            Entry { name: "Cid".into(), score: 180, solved: 9, penalty: 1 },
