#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Task {
    pub id: u32,
    pub title: &'static str,
    pub active: bool,
    pub archived: bool,
    pub blocked: bool,
    pub score: i32,
    pub tags: &'static [&'static str],
}

pub fn select_visible_titles(tasks: &[Task], required_tag: &str, limit: usize) -> Vec<String> {
    let mut items: Vec<&Task> = tasks
        .iter()
        .filter(|t| t.active)
        .filter(|t| t.score >= 0)
        .filter(|t| t.tags.iter().any(|tag| *tag == required_tag))
        .collect();

    items.sort_by_key(|t| t.score);

    items
        .into_iter()
        .take(limit)
        .map(|t| format!("{}#{}", t.title, t.id))
        .collect()
}

