#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Role {
    Guest,
    Member,
    Moderator,
    Admin,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Route {
    Home,
    Profile,
    AdminPanel,
    Billing,
    ModQueue,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    View,
    Edit,
    Delete,
    Refund,
    BanUser,
}

pub fn allow(role: Role, route: Route, action: Action) -> bool {
    match action {
        Action::View => match route {
            Route::Home => true,
            Route::Profile => role != Role::Guest,
            Route::AdminPanel => role == Role::Admin,
            Route::Billing => role != Role::Guest,
            Route::ModQueue => role == Role::Moderator,
        },
        Action::Edit => match route {
            Route::Home => false,
            Route::Profile => matches!(role, Role::Member | Role::Moderator | Role::Admin),
            Route::AdminPanel => role == Role::Admin,
            Route::Billing => role == Role::Member,
            Route::ModQueue => role == Role::Moderator,
        },
        Action::Delete => match route {
            Route::Home => false,
            Route::Profile => role == Role::Admin,
            Route::AdminPanel => role == Role::Admin,
            Route::Billing => false,
            Route::ModQueue => role == Role::Moderator,
        },
        Action::Refund => match route {
            Route::Billing => role == Role::Admin,
            _ => false,
        },
        Action::BanUser => match route {
            Route::ModQueue => role == Role::Moderator,
            _ => false,
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn view_rules_cover_public_and_staff_pages() {
        assert!(allow(Role::Guest, Route::Home, Action::View));
        assert!(!allow(Role::Guest, Route::Profile, Action::View));
        assert!(allow(Role::Moderator, Route::ModQueue, Action::View));
        assert!(allow(Role::Admin, Route::ModQueue, Action::View));
        assert!(!allow(Role::Member, Route::AdminPanel, Action::View));
    }

    #[test]
    fn edit_rules_distinguish_profile_billing_and_queue() {
        assert!(allow(Role::Member, Route::Profile, Action::Edit));
        assert!(allow(Role::Admin, Route::Billing, Action::Edit));
        assert!(!allow(Role::Member, Route::ModQueue, Action::Edit));
        assert!(allow(Role::Admin, Route::ModQueue, Action::Edit));
    }

    #[test]
    fn delete_requires_admin_except_mod_queue_staff() {
        assert!(!allow(Role::Moderator, Route::Profile, Action::Delete));
        assert!(allow(Role::Admin, Route::Profile, Action::Delete));
        assert!(allow(Role::Moderator, Route::ModQueue, Action::Delete));
        assert!(allow(Role::Admin, Route::ModQueue, Action::Delete));
    }

    #[test]
    fn refund_is_billing_staff_only() {
        assert!(!allow(Role::Member, Route::Billing, Action::Refund));
        assert!(allow(Role::Moderator, Route::Billing, Action::Refund));
        assert!(allow(Role::Admin, Route::Billing, Action::Refund));
        assert!(!allow(Role::Admin, Route::Profile, Action::Refund));
    }

    #[test]
    fn ban_user_allowed_for_staff_in_moderation_surfaces_only() {
        assert!(!allow(Role::Moderator, Route::Profile, Action::BanUser));
        assert!(allow(Role::Moderator, Route::ModQueue, Action::BanUser));
        assert!(allow(Role::Admin, Route::ModQueue, Action::BanUser));
        assert!(allow(Role::Admin, Route::AdminPanel, Action::BanUser));
        assert!(!allow(Role::Member, Route::ModQueue, Action::BanUser));
    }
}

