#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub player: String,
    pub group: String,
    pub score: i32,
    pub attempts: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub player: String,
    pub group: String,
    pub total_score: i32,
    pub total_attempts: u32,
    pub rounds: usize,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<RankedPlayer> {
    let mut merged: Vec<RankedPlayer> = Vec::new();

    for e in entries {
        if let Some(existing) = merged.iter_mut().find(|r| r.player == e.player) {
            existing.total_score = e.score;
            existing.total_attempts = e.attempts;
            existing.rounds += 1;
        } else {
            merged.push(RankedPlayer {
                rank: 0,
                player: e.player.clone(),
                group: e.group.clone(),
                total_score: e.score,
                total_attempts: e.attempts,
                rounds: 1,
            });
        }
    }

    merged.sort_by(|a, b| {
        b.total_score
            .cmp(&a.total_score)
            .then_with(|| a.player.cmp(&b.player))
    });

    for (idx, row) in merged.iter_mut().enumerate() {
        row.rank = idx + 1;
    }

    merged
}

#[cfg(test)]
mod tests {
    use super::*;

    fn e(player: &str, group: &str, score: i32, attempts: u32) -> Entry {
        Entry {
            player: player.to_string(),
            group: group.to_string(),
            score,
            attempts,
        }
    }

    #[test]
    fn merges_duplicate_players_and_ranks_densely() {
        let rows = vec![
            e("alpha", "red", 30, 4),
            e("beta", "blue", 50, 3),
            e("alpha", "red", 20, 2),
            e("gamma", "green", 50, 2),
            e("delta", "yellow", 15, 1),
            e("beta", "blue", 5, 1),
        ];

        let board = leaderboard(&rows);
        let got: Vec<(usize, &str, i32, u32, usize)> = board
            .iter()
            .map(|r| (r.rank, r.player.as_str(), r.total_score, r.total_attempts, r.rounds))
            .collect();

        assert_eq!(
            got,
            vec![
                (1, "gamma", 50, 2, 1),
                (1, "beta", 55, 4, 2),
                (2, "alpha", 50, 6, 2),
                (3, "delta", 15, 1, 1),
            ]
        );
    }

    #[test]
    fn tie_breaks_on_attempts_then_group_then_player() {
        let rows = vec![
            e("zane", "beta", 40, 3),
            e("amy", "delta", 40, 3),
            e("mira", "alpha", 40, 3),
            e("nova", "gamma", 40, 2),
        ];

        let board = leaderboard(&rows);
        let got: Vec<(usize, &str, &str, i32, u32)> = board
            .iter()
            .map(|r| (
                r.rank,
                r.player.as_str(),
                r.group.as_str(),
                r.total_score,
                r.total_attempts,
            ))
            .collect();

        assert_eq!(
            got,
            vec![
                (1, "nova", "gamma", 40, 2),
                (2, "mira", "alpha", 40, 3),
                (2, "zane", "beta", 40, 3),
                (2, "amy", "delta", 40, 3),
            ]
        );
    }

    #[test]
    fn duplicate_merge_uses_lexicographically_smallest_group() {
        let rows = vec![
            e("ivy", "zeta", 10, 1),
            e("ivy", "alpha", 15, 2),
            e("omar", "beta", 24, 2),
        ];

        let board = leaderboard(&rows);

        assert_eq!(board[0].player, "ivy");
        assert_eq!(board[0].group, "alpha");
        assert_eq!(board[0].total_score, 25);
        assert_eq!(board[0].total_attempts, 3);
        assert_eq!(board[0].rank, 1);
        assert_eq!(board[1].rank, 2);
    }

    #[test]
    fn exact_duplicates_do_not_increase_round_count() {
        let rows = vec![
            e("kai", "red", 7, 1),
            e("kai", "red", 7, 1),
            e("luz", "blue", 6, 1),
        ];

        let board = leaderboard(&rows);
        let kai = board.iter().find(|r| r.player == "kai").unwrap();

        assert_eq!(kai.total_score, 7);
        assert_eq!(kai.total_attempts, 1);
        assert_eq!(kai.rounds, 1);
        assert_eq!(kai.rank, 1);
    }
}

